class Solution:
    def distanceTraveled(self, mainTank: int, additionalTank: int) -> int:
        distance = 0
        while mainTank >= 5:
            mainTank -= 5
            distance += 5
            if additionalTank >= 1:
                additionalTank -= 1
                mainTank += 1
        distance += mainTank
        return distance * 10

